import pygame
import random
from typing import List, Tuple, Optional
from dataclasses import dataclass

# Import game constants and data structures from task2 and task3 and task4
from task2 import (
    GRID_WIDTH, GRID_HEIGHT, CELL_SIZE,
    TETROMINO_SHAPES, SHAPE_COLORS,
    GEM_COLORS, ScoreTracker,
    SCREEN_WIDTH, SCREEN_HEIGHT, FPS
)
from task3 import (
    draw_grid, draw_tetromino, draw_next_tetromino,
    draw_score, render, font
)
from task4 import handle_input  # only input handler needed

# -----------------------------------------------------------------------------
# Data Structures
# -----------------------------------------------------------------------------
GridType = List[List[Optional[Tuple[int, int, int]]]]

@dataclass
class Tetromino:
    shape_key: str
    rotation: int
    position: Tuple[int, int]
    color: Tuple[int, int, int]

    @property
    def blocks(self) -> List[Tuple[int, int]]:
        offsets = TETROMINO_SHAPES[self.shape_key][self.rotation]
        r0, c0 = self.position
        return [(r0 + dr, c0 + dc) for dr, dc in offsets]

# -----------------------------------------------------------------------------
# Game State
# -----------------------------------------------------------------------------
GRID: GridType = [[None for _ in range(GRID_WIDTH)] for _ in range(GRID_HEIGHT)]
CURRENT_TETROMINO: Optional[Tetromino] = None
NEXT_TETROMINO: Optional[Tetromino] = None
score_tracker = ScoreTracker()

# -----------------------------------------------------------------------------
# Tetromino Spawning
# -----------------------------------------------------------------------------
def new_tetromino() -> Tetromino:
    shape_key = random.choice(list(TETROMINO_SHAPES.keys()))
    return Tetromino(
        shape_key=shape_key,
        rotation=0,
        position=(0, GRID_WIDTH // 2 - 2),
        color=SHAPE_COLORS[shape_key]
    )

def spawn_tetromino() -> bool:
    global CURRENT_TETROMINO, NEXT_TETROMINO

    if NEXT_TETROMINO is None:
        CURRENT_TETROMINO = new_tetromino()
        NEXT_TETROMINO = new_tetromino()
    else:
        CURRENT_TETROMINO = NEXT_TETROMINO
        NEXT_TETROMINO = new_tetromino()

    if not valid_move(CURRENT_TETROMINO, GRID, 0, 0):
        return False  # Game over
    return True

# -----------------------------------------------------------------------------
# Movement and Rotation
# -----------------------------------------------------------------------------
def valid_move(tetromino: Tetromino, grid: GridType, row_offset: int, col_offset: int) -> bool:
    for row, col in tetromino.blocks:
        r, c = row + row_offset, col + col_offset
        if r < 0 or r >= GRID_HEIGHT or c < 0 or c >= GRID_WIDTH:
            return False
        if 0 <= r < GRID_HEIGHT and 0 <= c < GRID_WIDTH and grid[r][c] is not None:
            return False
    return True

def move_tetromino_internal(t: Tetromino, grid: GridType, dr: int, dc: int) -> bool:
    if valid_move(t, grid, dr, dc):
        t.position = (t.position[0] + dr, t.position[1] + dc)
        return True
    return False

def rotate_tetromino_internal(t: Tetromino, grid: GridType) -> bool:
    orig_rot = t.rotation
    new_rot = (orig_rot + 1) % len(TETROMINO_SHAPES[t.shape_key])
    temp = Tetromino(t.shape_key, new_rot, t.position, t.color)

    # try kicks
    for kick in [(0,0),(0,-1),(0,1),(-1,0),(1,0)]:
        temp.position = (t.position[0]+kick[0], t.position[1]+kick[1])
        if valid_move(temp, grid, 0, 0):
            t.rotation = new_rot
            t.position = temp.position
            return True
    return False

# -----------------------------------------------------------------------------
# Locking and Clearing
# -----------------------------------------------------------------------------
def lock_tetromino(t: Tetromino, grid: GridType) -> None:
    for r, c in t.blocks:
        if 0 <= r < GRID_HEIGHT and 0 <= c < GRID_WIDTH:
            grid[r][c] = t.color

def check_tetris_clear(grid: GridType) -> List[int]:
    return [i for i, row in enumerate(grid) if all(cell is not None for cell in row)]

def clear_lines(grid: GridType, lines: List[int]) -> None:
    for idx in sorted(lines, reverse=True):
        del grid[idx]
        grid.insert(0, [None] * GRID_WIDTH)
    score_tracker.add_tetris_clear(len(lines))

# -----------------------------------------------------------------------------
# Match-3 Logic
# -----------------------------------------------------------------------------
def check_match_3(grid: GridType) -> List[Tuple[int,int]]:
    matches = []
    # horizontal
    for r in range(GRID_HEIGHT):
        for c in range(GRID_WIDTH - 2):
            if grid[r][c] and grid[r][c] == grid[r][c+1] == grid[r][c+2]:
                matches += [(r,c),(r,c+1),(r,c+2)]
    # vertical
    for c in range(GRID_WIDTH):
        for r in range(GRID_HEIGHT - 2):
            if grid[r][c] and grid[r][c] == grid[r+1][c] == grid[r+2][c]:
                matches += [(r,c),(r+1,c),(r+2,c)]
    # unique
    return list(dict.fromkeys(matches))

def clear_matches(grid: GridType, matches: List[Tuple[int,int]]) -> None:
    for r, c in matches:
        grid[r][c] = None
    score_tracker.add_match(len(matches))

def drop_floating_gems(grid: GridType) -> None:
    for c in range(GRID_WIDTH):
        stack = [grid[r][c] for r in range(GRID_HEIGHT) if grid[r][c] is not None]
        for r in range(GRID_HEIGHT):
            grid[r][c] = stack[r - (GRID_HEIGHT - len(stack))] if r >= GRID_HEIGHT - len(stack) else None

# -----------------------------------------------------------------------------
# Chain-Reaction Resolution
# -----------------------------------------------------------------------------
def resolve_grid(grid: GridType) -> None:
    any_clear = True
    while any_clear:
        any_clear = False
        lines = check_tetris_clear(grid)
        if lines:
            clear_lines(grid, lines)
            any_clear = True

        matches = check_match_3(grid)
        if matches:
            clear_matches(grid, matches)
            any_clear = True

        if any_clear:
            drop_floating_gems(grid)

# -----------------------------------------------------------------------------
# Main Game Loop
# -----------------------------------------------------------------------------
def main():
    global CURRENT_TETROMINO, NEXT_TETROMINO, GRID, score_tracker

    pygame.init()
    screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
    pygame.display.set_caption("Tetris-Bejeweled")
    clock = pygame.time.Clock()

    fall_speed = 1  # cells per second
    fall_interval = 1000 / fall_speed
    last_fall = pygame.time.get_ticks()

    game_over = not spawn_tetromino()
    running = True

    while running:
        now = pygame.time.get_ticks()
        # 1. Input
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            elif CURRENT_TETROMINO:
                handle_input(event, CURRENT_TETROMINO, GRID)

        # 2. Gravity & Lock
        if not game_over and (now - last_fall) >= fall_interval:
            if CURRENT_TETROMINO:
                if not move_tetromino_internal(CURRENT_TETROMINO, GRID, 1, 0):
                    lock_tetromino(CURRENT_TETROMINO, GRID)
                    resolve_grid(GRID)
                    if not spawn_tetromino():
                        game_over = True
            last_fall = now

        # 3. Rendering
        render(screen, GRID, CURRENT_TETROMINO, NEXT_TETROMINO, score_tracker.current)

        pygame.display.flip()
        clock.tick(FPS)

    pygame.quit()

if __name__ == "__main__":
    main()
